@@ -1860,9 +1860,28 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return CastInst::Create(Instruction::ZExt, NarrowMaxMin, II->getType());
       }
     }
-    // If both operands of unsigned min/max are sign-extended, it is still ok
-    // to narrow the operation.
-    [[fallthrough]];
+    // umax(shl nuw x, 1, add x, 1) --> select (x == 0), 1, shl nuw x, 1
+    // When x=0: shl(0,1)=0, add(0,1)=1, umax=1
+    // When x>=1: shl(x,1)=2x >= x+1=add(x,1), umax=shl(x,1)
+    {
+      const APInt *ShlAmt, *AddC;
+      Value *ShlVal = nullptr;
+      if (match(I0, m_OneUse(m_NUWShl(m_Value(X), m_APInt(ShlAmt)))) &&
+          match(I1, m_OneUse(m_Add(m_Value(Y), m_APInt(AddC)))) &&
+          X == Y && *ShlAmt == 1 && *AddC == 1) {
+        ShlVal = I0;
+      } else if (match(I1, m_OneUse(m_NUWShl(m_Value(X), m_APInt(ShlAmt)))) &&
+                 match(I0, m_OneUse(m_Add(m_Value(Y), m_APInt(AddC)))) &&
+                 X == Y && *ShlAmt == 1 && *AddC == 1) {
+        ShlVal = I1;
+      }
+      if (ShlVal) {
+        Value *Cmp = Builder.CreateICmpEQ(X, ConstantInt::getNullValue(X->getType()));
+        Value *Sel = Builder.CreateSelect(Cmp, ConstantInt::get(II->getType(), 1), ShlVal);
+        return replaceInstUsesWith(CI, Sel);
+      }
+    }
+    break;
   }
